def pluck(arr):
    result = []
    if not arr:
        return result
    even_nodes = [(node, i) for i, node in enumerate(arr) if node % 2 == 0]
    if not even_nodes:
        return result
    smallest_even_node = min(even_nodes, key=lambda x: (x[0], x[1]))
    result = [smallest_even_node[0], smallest_even_node[1]]
    return result

