import numpy as np

def find_zero(xs: list) -> float:
    if len(xs) % 2 != 0:
        raise ValueError("xs must have an even number of coefficients")
    if max(i for i in xs if i != 0) == 0:
        raise ValueError("xs must have a largest non-zero coefficient")

    coeffs = np.poly1d(xs)
    roots = np.roots(coeffs)
    for root in roots:
        if abs(root.imag) < 1e-6:  # check for real roots
            return round(root.real, 2)
    return None
