import numpy as np

def find_zero(xs: list) -> float:
    """
    Find the zero point of a polynomial.
    """
    if len(xs) % 2 != 0:
        raise ValueError("xs must have an even number of coefficients")
    a = np.array(xs)
    return round(np.roots(a)[0].real, 2)

